            (4228, 48, 'Price is subjected to change without any prior notification based on amendment from authorized bodies. Price will be applicable as per M&M online portal as on delivery date and time.', 0, 0, '4226', 1, '2021-10-07 20:17:53', 1, '2021-10-19 14:35:33', 1, '2021-10-19 14:35:33', NULL),
            (4229, 48, 'All the Customers are requested to make payment either in BMPL Bank Account or at Cash Counter at Bikaner and Churu Branch Only. As per Govt. Guidelines, Cash payment of more than INR 2 lakhs cannot be accepted.', 0, 0, '4226', 1, '2021-10-07 20:17:53', 1, '2021-10-19 14:35:33', 1, '2021-10-19 14:35:33', NULL),
            (4230, 48, 'Facilities like Vehicle Registration, Accessories Fitment, RSA, Extended Warranty are provided at dealership only, payment against such facilities should be deposited at Bikaner Motors and payment receipt must be taken from cashier. None of our employee provide any mentioned facility from market / broker and do not accept payment against any mentioned facility in personal capacity.', 0, 0, '4226', 1, '2021-10-07 20:17:53', 1, '2021-10-19 14:35:33', 1, '2021-10-19 14:35:33', NULL),
            (4231, 48, 'All the customers are informed that none of our employee is directed to take any payment without issuing deposit receipt to customer, please do not make any payment without payment receipt. Dealership is not liable for any payment made without deposit receipt.', 0, 0, '4226', 1, '2021-10-07 20:17:53', 1, '2021-10-19 14:35:33', 1, '2021-10-19 14:35:33', NULL),
            (4232, 48, 'Fitment of accessories from market vendors may lead to expiry of vehicles warranty.', 0, 0, '4226', 1, '2021-10-07 20:17:53', 1, '2021-10-19 14:35:33', 1, '2021-10-19 14:35:33', NULL),
            (4233, 48, 'Loyalty Discount cannot be clubbed with Exchange & Corporate Scheme', 0, 0, '4226', 1, '2021-10-07 20:17:53', 1, '2021-10-19 14:35:33', 1, '2021-10-19 14:35:33', NULL),
            (4234, 48, 'मय अिधक ू ृ त िनकाय से संशोधन के आधार पर िबना िकसी पवू  सचना के बदल सकता है। िडलीवरी की तारीख और समय पर मिहंद ू  ा ऑनलाइन पोटल के अनुसार वाहन की कीमत लाग होगी। ू', 4228, 0, '4227', 1, '2021-10-07 20:17:53', 1, '2021-10-19 14:35:33', 1, '2021-10-19 14:35:33', NULL),
            (4235, 48, 'सभी गाहक से अनुरोध है िक वे या तो BMPL के ब क खाते म या के वल बीकानेर और च शाखा के कै श काउंटर पर ही भ ू ुगतान कर । सरकारी िदशािनदशों के अनुसार, 2 लाख पये से अिधक का नकद भुगतान वीकार नहीं िकया जा सकता है।', 4229, 0, '4227', 1, '2021-10-07 20:17:53', 1, '2021-10-19 14:35:33', 1, '2021-10-19 14:35:33', NULL),
            (4236, 48, 'डीलरिशप पर हीकल रिजटे शन, एसेसरीज िफटम ट, आरएसए, एसट डेड वारंटी जैसी स  ुिवधाएं दी जाती ह , ऐसी सुिवधाओं के िलए भुगतान बीकानेर मोटस म िकया जाना चािहए और भुगतान रसीद कै िशयर से लेनी होगी। हमारा कोई भी कमचारी बाज़ार / बोकर से कोई उलेिखत सुिवधा नहीं देता है और यितगत मता म िकसी भी उलेिखत सुिवधा के िलए भुगतान वीकार नहीं करता है।', 4230, 0, '4227', 1, '2021-10-07 20:17:53', 1, '2021-10-19 14:35:33', 1, '2021-10-19 14:35:33', NULL),
            (4237, 48, 'सभी गाहक को सिचत िकया जाता है िक हमारा कोई भी कम ू चारी गाहक को जमा रसीद जारी िकए िबना कोई भुगतान लेने के िलए िनदिशत नहीं है, कृ पया भुगतान रसीद के िबना कोई भुगतान न कर । भुगतान रसीद िलए बग़ैर िकए गए िकसी भी भुगतान के िलए डीलरिशप उरदायी नहीं है।', 4231, 0, '4227', 1, '2021-10-07 20:17:53', 1, '2021-10-19 14:35:33', 1, '2021-10-19 14:35:33', NULL),
