            (4279, 48, 'Price is subjected to change without any prior notification based on amendment from authorized bodies. Price will be applicable as per M&M online portal as on delivery date and time.', 0, 0, '4226', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4280, 48, 'मूल्य अधिकृत निकायों से संशोधन के आधार पर बिना किसी पूर्व सूचना के बदल सकता है। डिलीवरी की तारीख और समय पर महिंद्रा ऑनलाइन पोर्टल के अनुसार वाहन की कीमत लागू होगी।', 4279, 0, '4227', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4281, 48, 'All the Customers are requested to make payment either in BMPL Bank Account or at Cash Counter at Bikaner and Churu Branch Only. As per Govt. Guidelines, Cash payment of more than INR 2 lakhs cannot be accepted.', 0, 0, '4226', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4282, 48, 'सभी ग्राहकों से अनुरोध है कि वे या तो BMPL के बॅंक खाते में या केवल बीकानेर और चुरु शाखा के कॅश काउंटर पर ही भुगतान करें। सरकारी दिशानिर्देशों के अनुसार 2 लाख रुपये से अधिक का नकद भुगतान स्वीकार नहीं किया जा सकता है।', 4281, 0, '4227', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4283, 48, 'Facilities like Vehicle Accessories Fitment, RSA, Extended Warranty are provided at dealership only, payment against such facilities should be deposited at Cash Counter of Bikaner Motors and Cashier will provide the receipt to customer at that time only. None of our employee provide any mentioned facility from market retailers and also do not accept payment against any mentioned facility in personal capacity.', 0, 0, '4226', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4284, 48, 'डीलरशिप पर वाहन की एसेसरीस फिटमेंट, RSA, एक्सटेंडेड वॉरेंटी जैसी सुविधायें दी जाती हैं, ऐसी सुविधाओं के लिए भुगतान स्वयं ग्राहक द्वारा बीकानेर मोटर्स के कॅश काउंटर पर किया जाना है और भुगतान रसीद कॅशियर द्वारा ग्राहक को मुहैय्या करवाई जाएगी। हमारा कोई भी कर्मचारी ये सुविधायें बाज़ार के किसी विक्रेता से मुहैया नही करवाता है और व्यक्तिगत क्षमता में किसी भी उल्लिखित सुविधा के लिए भुगतान स्वीकार नही करता है।', 4283, 0, '4227', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4285, 48, 'All the customers are informed that none of our employee is directed to take any payment without issuing deposit receipt to customer, please do not make any payment without payment receipt. Dealership is not liable for any payment made without deposit receipt.', 0, 0, '4226', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4286, 48, 'सभी ग्राहकों को सूचित किया जाता है कि हमारा कोई भी टीम मेंबर ग्राहक से नकद भुगतान नही लेता है, ग्राहकों से अनुरोध है कि भुगतान की रसीद अवश्य लेवे। बिना रसीद के किए गये भुगतान के लिए डीलरशिप ज़िम्मेदार नही होगी।', 4285, 0, '4227', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4287, 48, 'Fitment of accessories from market vendors may lead to expiry of vehicles warranty. Especially electronic equipments fitment from market retailers may lead to fault in electrical system iof vehicle, which is not covered in warranty.', 0, 0, '4226', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4288, 48, 'बाज़ार के विक्रेताओं से एससरीस फिट करवाने पर गाड़ी की वॉरेंटी समाप्त हो सकती है। ख़ास तौर पर बाज़ार से एलेक्ट्रॉनिक सामान फिटमेंट करवाने पर गाड़ी के एलेक्ट्रिकल सिस्टम में फॉल्ट आने की संभावना ज़्यादा रहती है, जो वॉरेंटी में कवर नही होगा ।', 4287, 0, '4227', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4289, 48, 'Loyalty Discount cannot be clubbed with Exchange & Corporate Scheme', 0, 0, '4226', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
            (4290, 48, 'लायल्टी और एक्सचेंज स्कीम को एक साथ जोड़ कर नही दिया जा सकता है।', 4289, 0, '4227', 1, '2021-10-26 00:48:15', 1, '2021-10-26 00:48:15', 1, NULL, NULL),
